def dump(path,obj):
 p=ROOT/path;p.parent.mkdir(parents=True,exist_ok=True);p.write_text(json.dumps(obj,ensure_ascii=False,indent=2)+'\n',encoding='utf-8')

def svg_card(path,title,subtitle,chapter,index,kind):
 p=ROOT/path;p.parent.mkdir(parents=True,exist_ok=True)
 title=html.escape(title);subtitle=html.escape(subtitle);marks=['≋','▥','⚓','✹','◉','♜','⌂','𐀀','◇','◷'];acc=['#5e9cb7','#d4a55f','#4f9ab0','#b67a5a','#d08d63','#c8a05b','#8a9caa','#d5b86b','#5b8ea8','#9a7a62'][chapter-1]
 p.write_text(f'''<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 720 900" role="img" aria-label="{title}"><defs><linearGradient id="g" x2="1" y2="1"><stop stop-color="#071014"/><stop offset=".55" stop-color="#1a2a31"/><stop offset="1" stop-color="#08090b"/></linearGradient><radialGradient id="r"><stop stop-color="{acc}" stop-opacity=".42"/><stop offset="1" stop-color="{acc}" stop-opacity="0"/></radialGradient></defs><rect width="720" height="900" fill="url(#g)"/><circle cx="565" cy="170" r="260" fill="url(#r)"/><path d="M0 680 C120 600 260 730 420 655 S620 610 720 645 V900 H0Z" fill="#050708" opacity=".92"/><path d="M62 112 H658 M62 790 H658" stroke="{acc}" stroke-width="2" opacity=".8"/><text x="62" y="82" fill="{acc}" font-size="21" font-family="Arial" letter-spacing="4">AEGEAN · BRONZE AGE · {chapter:02d}</text><text x="560" y="355" text-anchor="middle" fill="{acc}" font-size="170" font-family="serif" opacity=".85">{marks[chapter-1]}</text><path d="M100 450 C220 410 320 500 430 450 S590 420 650 455" fill="none" stroke="{acc}" stroke-width="7" opacity=".35"/><text x="62" y="654" fill="#fff8e9" font-size="43" font-family="Georgia">{title[:30]}</text><text x="62" y="710" fill="#d8d0c2" font-size="23" font-family="Arial">{subtitle[:52]}</text><text x="62" y="832" fill="{acc}" font-size="18" font-family="Arial" letter-spacing="3">{kind.upper()} · CODEX OF HISTORY · {index:02d}</text></svg>''',encoding='utf-8')

